#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=20005;
unordered_map<string,int> cnt;
unordered_map<string,bool> vis;
string s[N];
int n,ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>s[i];
		vis.clear();
		for(int j=0;j<s[i].size();j++)
		{
			string tmp="";
			for(int k=j;k<s[i].size();k++)
			{
				tmp+=s[i][k];
//				cout<<tmp<<"\n";
				if(vis.count(tmp)) continue;
				vis[tmp]=1;
				cnt[tmp]++;
//				cout<<"aaaaaaaaaaaaa\n";
			}
		}
	}
	int ans=0;
	for(int i=1;i<=n;i++) 
	{
		ans+=cnt[s[i]];
//		cout<<cnt[s[i]]<<" ";
	}
	cout<<ans-n;
	return 0;
}
